"""A shopping cart with item management and discount support."""

from __future__ import annotations

from dataclasses import dataclass, field
from decimal import Decimal
from enum import Enum
from typing import Iterator


class CartError(Exception):
    """Base exception for all shopping cart errors."""


class ItemNotFoundError(CartError):
    """Raised when an operation references a product not present in the cart."""

    def __init__(self, product_name: str) -> None:
        super().__init__(f"No item named {product_name!r} exists in the cart.")
        self.product_name = product_name


class DuplicateItemError(CartError):
    """Raised when adding a product that already exists in the cart."""

    def __init__(self, product_name: str) -> None:
        super().__init__(
            f"An item named {product_name!r} is already in the cart; "
            f"update its quantity instead."
        )
        self.product_name = product_name


class InvalidPriceError(CartError):
    """Raised when a unit price is negative."""

    def __init__(self, unit_price: Decimal) -> None:
        super().__init__(f"Unit price must not be negative, got {unit_price}.")
        self.unit_price = unit_price


class InvalidQuantityError(CartError):
    """Raised when a quantity is not a positive integer."""

    def __init__(self, quantity: int) -> None:
        super().__init__(f"Quantity must be a positive integer, got {quantity}.")
        self.quantity = quantity


class InvalidDiscountError(CartError):
    """Raised when a discount value is outside its permitted range."""

    def __init__(self, message: str) -> None:
        super().__init__(message)


class DiscountKind(Enum):
    """The two ways a discount can reduce the subtotal."""

    PERCENTAGE = "percentage"
    FLAT = "flat"


@dataclass(frozen=True)
class Discount:
    """An immutable discount applied to a cart's subtotal."""

    kind: DiscountKind
    value: Decimal

    def apply_to(self, subtotal: Decimal) -> Decimal:
        """Return the subtotal after this discount, never below zero."""
        if self.kind is DiscountKind.PERCENTAGE:
            reduced = subtotal * (Decimal(1) - self.value / Decimal(100))
        else:
            reduced = subtotal - self.value
        return max(reduced, Decimal(0))


@dataclass(frozen=True)
class CartItem:
    """A single line in the cart: a product, its unit price, and quantity."""

    product_name: str
    unit_price: Decimal
    quantity: int

    @property
    def line_total(self) -> Decimal:
        """Total cost for this line (unit price multiplied by quantity)."""
        return self.unit_price * self.quantity

    def with_quantity(self, new_quantity: int) -> CartItem:
        """Return a copy of this item with a different quantity."""
        return CartItem(self.product_name, self.unit_price, new_quantity)


class ShoppingCart:
    """A shopping cart that holds items and computes discounted totals.

    Items are keyed by product name, so each product appears at most once.
    Monetary amounts use :class:`decimal.Decimal` to avoid floating-point
    rounding errors.
    """

    def __init__(self) -> None:
        """Create an empty cart with no discount applied."""
        self._items: dict[str, CartItem] = {}
        self._discount: Discount | None = None

    def add_item(
        self, product_name: str, unit_price: Decimal, quantity: int
    ) -> CartItem:
        """Add a new item to the cart and return it.

        Raises:
            DuplicateItemError: If the product is already in the cart.
            InvalidPriceError: If the unit price is negative.
            InvalidQuantityError: If the quantity is not a positive integer.
        """
        if product_name in self._items:
            raise DuplicateItemError(product_name)
        self._validate_price(unit_price)
        self._validate_quantity(quantity)

        item = CartItem(product_name, unit_price, quantity)
        self._items[product_name] = item
        return item

    def remove_item(self, product_name: str) -> None:
        """Remove an item from the cart by product name.

        Raises:
            ItemNotFoundError: If no such product is in the cart.
        """
        self._require_item(product_name)
        del self._items[product_name]

    def update_quantity(self, product_name: str, new_quantity: int) -> CartItem:
        """Set the quantity of an existing item and return the updated item.

        Raises:
            ItemNotFoundError: If no such product is in the cart.
            InvalidQuantityError: If the quantity is not a positive integer.
        """
        existing_item = self._require_item(product_name)
        self._validate_quantity(new_quantity)

        updated_item = existing_item.with_quantity(new_quantity)
        self._items[product_name] = updated_item
        return updated_item

    def apply_percentage_discount(self, percentage: Decimal) -> None:
        """Apply a percentage discount (0–100) to the subtotal.

        Raises:
            InvalidDiscountError: If the percentage is outside 0–100.
        """
        if not Decimal(0) <= percentage <= Decimal(100):
            raise InvalidDiscountError(
                f"Discount percentage must be between 0 and 100, got {percentage}."
            )
        self._discount = Discount(DiscountKind.PERCENTAGE, percentage)

    def apply_flat_discount(self, amount: Decimal) -> None:
        """Apply a flat monetary discount to the subtotal.

        Raises:
            InvalidDiscountError: If the amount is negative.
        """
        if amount < Decimal(0):
            raise InvalidDiscountError(
                f"Flat discount must not be negative, got {amount}."
            )
        self._discount = Discount(DiscountKind.FLAT, amount)

    def clear_discount(self) -> None:
        """Remove any discount currently applied to the cart."""
        self._discount = None

    def calculate_subtotal(self) -> Decimal:
        """Return the sum of all line totals before any discount."""
        return sum(
            (item.line_total for item in self._items.values()),
            start=Decimal(0),
        )

    def calculate_total(self) -> Decimal:
        """Return the final total after applying any discount."""
        subtotal = self.calculate_subtotal()
        if self._discount is None:
            return subtotal
        return self._discount.apply_to(subtotal)

    def list_items(self) -> list[CartItem]:
        """Return all items in the cart as a list (a copy, safe to mutate)."""
        return list(self._items.values())

    def clear(self) -> None:
        """Remove all items and any discount from the cart."""
        self._items.clear()
        self._discount = None

    def __len__(self) -> int:
        """Return the number of distinct products in the cart."""
        return len(self._items)

    def __iter__(self) -> Iterator[CartItem]:
        """Iterate over the cart's items."""
        return iter(self._items.values())

    def __contains__(self, product_name: object) -> bool:
        """Return whether a product name is present in the cart."""
        return product_name in self._items

    def _require_item(self, product_name: str) -> CartItem:
        """Return the item for a product or raise if it is absent."""
        try:
            return self._items[product_name]
        except KeyError:
            raise ItemNotFoundError(product_name) from None

    @staticmethod
    def _validate_price(unit_price: Decimal) -> None:
        """Raise if a unit price is negative."""
        if unit_price < Decimal(0):
            raise InvalidPriceError(unit_price)

    @staticmethod
    def _validate_quantity(quantity: int) -> None:
        """Raise if a quantity is not a positive integer."""
        if not isinstance(quantity, int) or isinstance(quantity, bool) or quantity <= 0:
            raise InvalidQuantityError(quantity)
```

## Design notes

**Data modeling.** `CartItem` and `Discount` are frozen dataclasses — immutable value objects. Updates produce new instances (`with_quantity`) rather than mutating in place, which keeps state changes explicit and the items list safe to hand out.

**SRP.** Each method does one thing. Discount *math* lives in `Discount.apply_to`, not in the cart — so adding a new discount kind doesn't touch `calculate_total`. Validation is isolated in `_validate_price` / `_validate_quantity`, and lookup-or-raise is centralized in `_require_item`.

**DRY.** Lookups, price checks, and quantity checks each exist in exactly one place and are reused by every method that needs them.

**Exceptions.** A `CartError` base with specific subclasses (`ItemNotFoundError`, `DuplicateItemError`, etc.) lets callers catch precisely what they care about. Each carries the offending value as an attribute for programmatic handling.

**Correctness details.** `Decimal` avoids float rounding bugs in money math; discounts floor at zero so a large flat discount can't produce a negative total; the `bool` guard in `_validate_quantity` rejects `True`/`False`, which are technically `int` instances.

**Extras.** `__len__`, `__iter__`, and `__contains__` make the cart feel Pythonic without compromising the public API. No mutable default arguments, no prints — every method returns a value or `None` by intent.

A reasonable extension would be quantizing `calculate_total` to two decimal places (`.quantize(Decimal("0.01"))`); I left rounding to the presentation layer so the cart stays lossless internally.

